class IntentDataset(Dataset):
    def __init__(self, texts, labels, vocab, max_len):
        self.texts = texts
        self.labels = labels
        self.vocab = vocab
        self.max_len = max_len
        
    def __len__(self):
        return len(self.texts)
    
    def __getitem__(self, idx):
        text = self.texts[idx]
        label = self.labels[idx]
        
        tokens = [self.vocab.get(c, self.vocab['<UNK>']) for c in text.lower()]
        tokens = tokens[:self.max_len]
        tokens += [self.vocab['<PAD>']] * (self.max_len - len(tokens))
        
        return torch.tensor(tokens, dtype=torch.long), torch.tensor(label, dtype=torch.long)

def build_vocab(texts):
    chars = set()
    for t in texts:
        chars.update(t.lower())
    vocab = {'<PAD>': 0, '<UNK>': 1}
    for i, c in enumerate(sorted(chars), 2):
        vocab[c] = i
    return vocab

def train_model(model, train_loader, epochs, lr, model_name):
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=lr)
    
    print(f"\n{'='*40}")
    print(f"Training {model_name}")
    print(f"{'='*40}")
    
    for epoch in range(epochs):
        model.train()
        total_loss = 0
        correct = 0
        total = 0
        
        for batch_x, batch_y in train_loader:
            optimizer.zero_grad()
            outputs = model(batch_x)
            loss = criterion(outputs, batch_y)
            loss.backward()
            optimizer.step()
            
            total_loss += loss.item()
            _, predicted = torch.max(outputs, 1)
            correct += (predicted == batch_y).sum().item()
            total += batch_y.size(0)
        
        acc = correct / total
        
        if (epoch + 1) % 10 == 0:
            print(f"Epoch {epoch+1}/{epochs} | Loss: {total_loss/len(train_loader):.4f} | Acc: {acc:.3f}")
    
    # Final test on training data (overfitting is expected with tiny data)
    model.eval()
    correct = 0
    total = 0
    with torch.no_grad():
        for batch_x, batch_y in train_loader:
            outputs = model(batch_x)
            _, predicted = torch.max(outputs, 1)
            correct += (predicted == batch_y).sum().item()
            total += batch_y.size(0)
    
    final_acc = correct / total
    print(f"\nFinal Training Accuracy: {final_acc:.3f}")
    return model, final_acc

def main():
    os.makedirs("models", exist_ok=True)
    os.makedirs("data", exist_ok=True)
    
    texts = [t for t, _ in TRAINING_DATA]
    labels = [INTENT_TO_IDX[l] for _, l in TRAINING_DATA]
    
    vocab = build_vocab(texts)
    vocab_size = len(vocab)
    
    with open("data/vocab.pkl", "wb") as f:
        pickle.dump(vocab, f)
    
    with open("data/intent_map.json", "w") as f:
        json.dump(INTENT_TO_IDX, f)
    
    # Use ALL data for training (no validation split)
    train_dataset = IntentDataset(texts, labels, vocab, MAX_LEN)
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)
    
    # Train MLP
    from mlp_intent import MLPIntentClassifier
    mlp = MLPIntentClassifier(vocab_size, EMBED_DIM, [128, 64], len(INTENTS), MAX_LEN)
    mlp, mlp_acc = train_model(mlp, train_loader, EPOCHS, LR, "mlp")
    torch.save(mlp.state_dict(), "models/mlp_best.pt")
    
    # Train CNN
    from cnn_intent import CNNIntentClassifier
    cnn = CNNIntentClassifier(vocab_size, EMBED_DIM, 64, [2, 3, 4], len(INTENTS), MAX_LEN)
    cnn, cnn_acc = train_model(cnn, train_loader, EPOCHS, LR, "cnn")
    torch.save(cnn.state_dict(), "models/cnn_best.pt")
    
    print("\n" + "="*40)
    print(f"MLP Accuracy: {mlp_acc:.3f}")
    print(f"CNN Accuracy: {cnn_acc:.3f}")
    print("Models saved to ./models/")
    print("="*40)

if __name__ == '__main__':
    main()